(window.webpackJsonp=window.webpackJsonp||[]).push([[877],{857:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">rounds</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> mostVisited = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">n, rounds</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> count=<span class=\\"hljs-built_in\\">Array</span>(n).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;rounds.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> start=rounds[i<span class=\\"hljs-number\\">-1</span>]<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">let</span> end=rounds[i]<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=start;j!==end;j++){\\n            <span class=\\"hljs-keyword\\">if</span>(j&gt;end){\\n                j=(j+n) % n   \\n            }\\n            <span class=\\"hljs-keyword\\">if</span>(j===end)<span class=\\"hljs-keyword\\">break</span>\\n            count[j]++\\n        }\\n    }\\n    count[rounds[rounds.length<span class=\\"hljs-number\\">-1</span>]<span class=\\"hljs-number\\">-1</span>]++\\n    <span class=\\"hljs-keyword\\">let</span> max=<span class=\\"hljs-built_in\\">Math</span>.max.apply(<span class=\\"hljs-built_in\\">Math</span>,count)\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;count.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(count[i]===max){\\n            res.push(i+<span class=\\"hljs-number\\">1</span>)\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"most-visited-sector-in-a-circular-track","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570 <code>n</code> \u548c\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>rounds</code> \u3002\u6709\u4e00\u6761\u5706\u5f62\u8d5b\u9053\u7531 <code>n</code> \u4e2a\u6247\u533a\u7ec4\u6210\uff0c\u6247\u533a\u7f16\u53f7\u4ece <code>1</code> \u5230 <code>n</code> \u3002\u73b0\u5c06\u5728\u8fd9\u6761\u8d5b\u9053\u4e0a\u4e3e\u529e\u4e00\u573a\u9a6c\u62c9\u677e\u6bd4\u8d5b\uff0c\u8be5\u9a6c\u62c9\u677e\u5168\u7a0b\u7531 <code>m</code> \u4e2a\u9636\u6bb5\u7ec4\u6210\u3002\u5176\u4e2d\uff0c\u7b2c <code>i</code> \u4e2a\u9636\u6bb5\u5c06\u4f1a\u4ece\u6247\u533a <code>rounds[i - 1]</code> \u5f00\u59cb\uff0c\u5230\u6247\u533a <code>rounds[i]</code> \u7ed3\u675f\u3002\u4e3e\u4f8b\u6765\u8bf4\uff0c\u7b2c <code>1</code> \u9636\u6bb5\u4ece&nbsp;<code>rounds[0]</code>&nbsp;\u5f00\u59cb\uff0c\u5230&nbsp;<code>rounds[1]</code>&nbsp;\u7ed3\u675f\u3002</p>\\n\\n<p>\u8bf7\u4f60\u4ee5\u6570\u7ec4\u5f62\u5f0f\u8fd4\u56de\u7ecf\u8fc7\u6b21\u6570\u6700\u591a\u7684\u90a3\u51e0\u4e2a\u6247\u533a\uff0c\u6309\u6247\u533a\u7f16\u53f7 <strong>\u5347\u5e8f</strong> \u6392\u5217\u3002</p>\\n\\n<p>\u6ce8\u610f\uff0c\u8d5b\u9053\u6309\u6247\u533a\u7f16\u53f7\u5347\u5e8f\u9006\u65f6\u9488\u5f62\u6210\u4e00\u4e2a\u5706\uff08\u8bf7\u53c2\u89c1\u7b2c\u4e00\u4e2a\u793a\u4f8b\uff09\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/08/22/3rd45e.jpg\\" style=\\"height: 341px; width: 433px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 4, rounds = [1,3,1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2]\\n<strong>\u89e3\u91ca\uff1a</strong>\u672c\u573a\u9a6c\u62c9\u677e\u6bd4\u8d5b\u4ece\u6247\u533a 1 \u5f00\u59cb\u3002\u7ecf\u8fc7\u5404\u4e2a\u6247\u533a\u7684\u6b21\u5e8f\u5982\u4e0b\u6240\u793a\uff1a\\n1 --&gt; 2 --&gt; 3\uff08\u9636\u6bb5 1 \u7ed3\u675f\uff09--&gt; 4 --&gt; 1\uff08\u9636\u6bb5 2 \u7ed3\u675f\uff09--&gt; 2\uff08\u9636\u6bb5 3 \u7ed3\u675f\uff0c\u5373\u672c\u573a\u9a6c\u62c9\u677e\u7ed3\u675f\uff09\\n\u5176\u4e2d\uff0c\u6247\u533a 1 \u548c 2 \u90fd\u7ecf\u8fc7\u4e86\u4e24\u6b21\uff0c\u5b83\u4eec\u662f\u7ecf\u8fc7\u6b21\u6570\u6700\u591a\u7684\u4e24\u4e2a\u6247\u533a\u3002\u6247\u533a 3 \u548c 4 \u90fd\u53ea\u7ecf\u8fc7\u4e86\u4e00\u6b21\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 2, rounds = [2,1,2,1,2,1,2,1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>[2]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>n = 7, rounds = [1,3,5,7]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2,3,4,5,6,7]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>2 &lt;= n &lt;= 100</code></li>\\n\\t<li><code>1 &lt;= m &lt;= 100</code></li>\\n\\t<li><code>rounds.length == m + 1</code></li>\\n\\t<li><code>1 &lt;= rounds[i] &lt;= n</code></li>\\n\\t<li><code>rounds[i] != rounds[i + 1]</code> \uff0c\u5176\u4e2d <code>0 &lt;= i &lt; m</code></li>\\n</ul>\\n","title":"1560. \u5706\u5f62\u8d5b\u9053\u4e0a\u7ecf\u8fc7\u6b21\u6570\u6700\u591a\u7684\u6247\u533a","relatedTags":["\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1560"}')}}]);